import React from 'react';
import { ListGroup, Button } from 'react-bootstrap';

const FilterSidebar = ({ categories = [], selectedCategory, setSelectedCategory, handleClearFilters }) => {
  return (
    <>
      <h6>Categorías</h6>
      <ListGroup variant="flush">
        {categories.map((category) => (
          <ListGroup.Item key={category} action active={category === selectedCategory} onClick={() => setSelectedCategory(category)}>
            {category}
          </ListGroup.Item>
        ))}
      </ListGroup>
      <Button variant="light" className="w-100 mt-3" onClick={handleClearFilters}>Limpiar Filtros</Button>
    </>
  );
};

export default FilterSidebar;
